import React, { useState } from 'react';

const allProjects = [
  [
    { href: 'https://dimacalingtechnicaldocumentation.vercel.app/', img: '/images/technicaldocument.png', title: 'Technical Document Web Page', desc: 'A website in the form of a technical document.' },
    { href: 'https://dimacalingsurvey.vercel.app/', img: '/images/survey.png', title: 'Customer Satisfaction Survey', desc: 'A form that intakes customer feedback.' },
    { href: 'https://dimacalingtributepage.vercel.app/', img: '/images/tribute.png', title: 'Tribute Page', desc: 'A page that shows gratitude to my brother.' },
  ],
  [
    { href: 'https://dimacalingportfolio.vercel.app/', img: '/images/portfolio.png', title: 'Personal Portfolio', desc: 'A page showcasing my past works.' },
    { href: 'https://onlineportfoliocc1.vercel.app/', img: '/images/groupwebsite.png', title: 'Group Portfolio', desc: 'Simple web page we made in first-year of university.' },
  ],
];

const Projects = () => {
  const [current, setCurrent] = useState(0);
  const prev = () => setCurrent((c) => (c === 0 ? allProjects.length - 1 : c - 1));
  const next = () => setCurrent((c) => (c === allProjects.length - 1 ? 0 : c + 1));

  return (
    <section
      id="Projects"
      className="flex flex-col items-center px-10 pt-24 pb-16"
      style={{ background: '#0d1117' }}
    >
      <h1 className="font-bold text-4xl text-white text-center mb-10">My Projects</h1>

      <div className="relative w-full max-w-4xl">
        <div className="flex justify-center gap-6 flex-wrap">
          {allProjects[current].map((project, i) => (
            <a key={i} href={project.href} target="_blank" rel="noreferrer" className="no-underline" style={{ textDecoration: 'none' }}>
              <div
                className="rounded-xl overflow-hidden text-center transition-all duration-300 hover:-translate-y-2"
                style={{ width: '220px', background: '#161b22', border: '1px solid rgba(255,255,255,0.1)', boxShadow: '0 0 0 transparent' }}
                onMouseEnter={e => e.currentTarget.style.boxShadow = '0 15px 25px rgba(0,0,0,0.5)'}
                onMouseLeave={e => e.currentTarget.style.boxShadow = '0 0 0 transparent'}
              >
                <img src={project.img} alt={project.title} className="w-full object-cover" style={{ height: '150px' }} />
                <div className="p-4">
                  <h5 className="font-bold text-xs mb-1" style={{ color: '#004097' }}>{project.title}</h5>
                  <p className="text-xs text-gray-400">{project.desc}</p>
                </div>
              </div>
            </a>
          ))}
        </div>

        <button onClick={prev} className="absolute -left-6 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full text-white text-xl font-bold flex items-center justify-center transition hover:opacity-80" style={{ background: 'rgba(0,0,0,0.5)', border: 'none', cursor: 'pointer' }}>‹</button>
        <button onClick={next} className="absolute -right-6 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full text-white text-xl font-bold flex items-center justify-center transition hover:opacity-80" style={{ background: 'rgba(0,0,0,0.5)', border: 'none', cursor: 'pointer' }}>›</button>
      </div>

      <div className="flex gap-2 mt-8">
        {allProjects.map((_, i) => (
          <button key={i} onClick={() => setCurrent(i)} className="w-3 h-3 rounded-full border-0 cursor-pointer transition-all" style={{ background: i === current ? '#ffffff' : 'rgba(255,255,255,0.3)' }} />
        ))}
      </div>
    </section>
  );
};

export default Projects;
